const urls = $json.urls || [];
if (!Array.isArray(urls) || urls.length === 0) throw new Error('body.urls 배열이 필요합니다.');
return urls.map((url) => ({ json: { url, targetLanguage: $json.targetLanguage, feedback: $json.feedback, focus: $json.focus } }));

