const all = $input.all().map(i => i.json);
const avg = all.length ? all.reduce((s,x)=>s + (Number(x.quality_score)||0),0)/all.length : 0;
return [{ json: { ok:true, count: all.length, average_quality_score: Number(avg.toFixed(2)), summaries: all } }];
